sql:
SELECT strftime('%Y', report_date) AS year, COUNT(report_id) AS report_count
FROM report_logs
GROUP BY year;

SELECT state_code, SUM(total_population) AS total_population
FROM disability_statistics
GROUP BY state_code;

SELECT ds.year, SUM(ds.total_disabled_population) AS total_disabled_population
FROM disability_statistics ds
GROUP BY ds.year;

SELECT u.username, u.role, u.department
FROM users u
INNER JOIN disability_statistics ds ON u.username = ds.area_name;

external_knowledge:
- 'that particular state' refers to 'State A';
- 'last year' refers to the year 2022;
- 'folks who have disabilities' refers to the total_disabled_population;
- 'the share of the whole population they represent' means the percentage of the disabled population in relation to the total population.

sql:
SELECT area_name, total_disabled_population, year
FROM disability_statistics
ORDER BY year DESC;

SELECT gender, SUM(total_disabled_population) AS total_disabled_population
FROM gender_distribution
GROUP BY gender;

external_knowledge:
- 'regions' refers to 'districts';
- 'folks with disabilities' refers to 'disabled population';
- 'share of the entire region's disabled population' means the percentage of disabled people in each district relative to the total number of disabled people across all districts.

sql:
SELECT age_group
FROM age_groups
WHERE age_group_id = 10;

SELECT age_group, total_disabled_population
FROM age_groups
ORDER BY age_group ASC;
